#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <cuda.h>

#define _QUEENS_BLOCK_SIZE_   128
#define _EMPTY_      -1

typedef struct queen_root{
  unsigned int control;
  int8_t board[12];
} QueenRoot;

inline __host__ __device__ void prefixesHandleSol(QueenRoot *root_prefixes, unsigned int flag,
                              const char *board, int initialDepth, int num_sol)
{
  root_prefixes[num_sol].control = flag;
  for(int i = 0; initialDepth > i;++i)
    root_prefixes[num_sol].board[i] = board[i];
}

inline __host__ __device__ bool MCstillLegal(const char *board, const int r)
{
  for (int i = 0; r > i; ++i)
    if (board[r] == board[i]) return false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r-1; 0 <= i; --i) {
    --ld; ++rd;
    if (ld == board[i] || rd == board[i]) return false;
  }
  return true;
}

__device__ bool queens_stillLegal(const char *board, const int r)
{
  bool safe = true;

  for (int i = 0; r > i; ++i)
    if (board[r] == board[i]) safe = false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r-1; 0 <= i; --i) {
    --ld; ++rd;
    if (ld == board[i] || rd == board[i]) safe = false;
  }
  return safe;
}

__global__ void BP_queens_root_dfs_kernel(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict root_prefixes,
  unsigned long long *__restrict vector_of_tree_size,
  unsigned long long *__restrict sols)
{
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (idx >= nPreFixos) return;

  unsigned int flag = 0;
  unsigned int bit_test = 0;
  char vertice[20];
  int N_l = N;
  int i, depth;
  unsigned long long  qtd_solutions_thread = 0ULL;
  int depthGlobal = depthPreFixos;
  unsigned long long tree_size = 0ULL;

#pragma unroll 2
  for (i = 0; N_l > i; ++i) {
    vertice[i] = _EMPTY_;
  }

  flag = root_prefixes[idx].control;

#pragma unroll 2
  for (i = 0; depthGlobal > i; ++i)
    vertice[i] = root_prefixes[idx].board[i];

  depth = depthGlobal;

  do {
    vertice[depth]++;
    bit_test = 0;
    bit_test = bit_test | (1<<vertice[depth]);
    if(N_l == vertice[depth]){
      vertice[depth] = _EMPTY_;
    } else if (!(flag & bit_test ) && queens_stillLegal(vertice, depth)){
      ++tree_size;
      flag = flag | (1ULL<<vertice[depth]);
      depth++;
      if (N_l == depth) {
        ++qtd_solutions_thread;
      } else continue;
    } else continue;
    depth--;
    flag = flag & (~(1ULL<<vertice[depth]));
  } while(depthGlobal <= depth);

  sols[idx] = qtd_solutions_thread;
  vector_of_tree_size[idx] = tree_size;
}

void BP_queens_root_dfs(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict root_prefixes,
  unsigned long long *__restrict vector_of_tree_size,
  unsigned long long *__restrict sols)
{
  int threads = _QUEENS_BLOCK_SIZE_;
  int blocks = (nPreFixos + threads - 1) / threads;

  QueenRoot *d_root_prefixes;
  unsigned long long *d_vector_of_tree_size;
  unsigned long long *d_sols;

  cudaMalloc(&d_root_prefixes, sizeof(QueenRoot)*nPreFixos);
  cudaMalloc(&d_vector_of_tree_size, sizeof(unsigned long long)*nPreFixos);
  cudaMalloc(&d_sols, sizeof(unsigned long long)*nPreFixos);

  cudaMemcpy(d_root_prefixes, root_prefixes, sizeof(QueenRoot)*nPreFixos, cudaMemcpyHostToDevice);

  BP_queens_root_dfs_kernel<<<blocks, threads>>>(N, nPreFixos, depthPreFixos, d_root_prefixes, d_vector_of_tree_size, d_sols);
  cudaDeviceSynchronize();

  cudaMemcpy(vector_of_tree_size, d_vector_of_tree_size, sizeof(unsigned long long)*nPreFixos, cudaMemcpyDeviceToHost);
  cudaMemcpy(sols, d_sols, sizeof(unsigned long long)*nPreFixos, cudaMemcpyDeviceToHost);

  cudaFree(d_root_prefixes);
  cudaFree(d_vector_of_tree_size);
  cudaFree(d_sols);
}

unsigned long long BP_queens_prefixes(int size, int initialDepth,
                                      unsigned long long *tree_size,
                                      QueenRoot *root_prefixes)
{
  unsigned int flag = 0;
  int bit_test = 0;
  char vertice[20];
  int i, nivel;
  unsigned long long local_tree = 0ULL;
  unsigned long long num_sol = 0;

  for (i = 0; size > i; ++i) {
    vertice[i] = -1;
  }

  nivel = 0;

  do{

    vertice[nivel]++;
    bit_test = 0;
    bit_test = bit_test | (1<<vertice[nivel]);

    if(size == vertice[nivel]){
      vertice[nivel] = _EMPTY_;
    }else if ( MCstillLegal(vertice, nivel) && !(flag &  bit_test ) ){

      flag = flag | (1ULL<<vertice[nivel]);
      nivel++;
      ++local_tree;
      if (initialDepth == nivel){
        prefixesHandleSol(root_prefixes,flag,vertice,initialDepth,num_sol);
        num_sol++;
      }else continue;
    }else continue;

    nivel--;
    flag = flag & (~(1ULL<<vertice[nivel]));

  }while(0 <= nivel);

  *tree_size = local_tree;

  return num_sol;
}


void nqueens(short size, int initial_depth, unsigned int n_explorers, QueenRoot *root_prefixes_h ,
             unsigned long long *vector_of_tree_size_h, unsigned long long *sols_h, const int repeat)
{
  printf("\n### Regular BP-DFS search. ###\n");

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; repeat > i; i++) {
    BP_queens_root_dfs(size,
                       n_explorers,
                       initial_depth,
                       root_prefixes_h,
                       vector_of_tree_size_h,
                       sols_h);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);
}


